#include <bits/stdc++.h>
using namespace std;
int n,a[10];
void dfs(int x,int last,int rest){
    if(rest==0 && x>2){
        printf("%d",a[1]);
        for(int i=2;i<x;i++)
            printf("+%d",a[i]);
        printf("\n");
        return;
    }
    for(int i=last;i<=rest;i++)
        a[x]=i,dfs(x+1,i,rest-i);
}
int main(){
    scanf("%d",&n);
    dfs(1,1,n);
    return 0;
}
